// Normalize incoming document records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    docId: String(j.docId ?? j.id ?? '').trim(),
    content: typeof j.content === 'string' ? j.content.trim() : j.content ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

// Build a stable idempotency key per document (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.docId, j.content].join('|')) } };
});

// Advance the incremental watermark to the newest record seen
const items = $input.all().map(i => i.json);
const newest = items.reduce((m, j) => {
  const ts = new Date(j.updatedAt || j.receivedAt || 0).getTime();
  return ts > m ? ts : m;
}, 0);
return [{ json: { watermark: new Date(newest || Date.now()).toISOString(), processed: items.length } }];
